    postprocess?(markdown: string): string;
    /**
     * 通用方法：检测 URL 是否匹配指定域名
     * @param url 要检测的 URL
     * @param domains 域名列表，如 ['36kr.com', 'm.36kr.com']
     */
    protected matchDomain(url: string, domains: string[]): boolean;
